// ============================================
// 服务定义
// ============================================
type ReportService interface {
	// 创建报告（异步处理）
	// 立即返回 report_id，后台异步查询和聚合数据
	// 会自动对所有聚合类型（avg, min, max, count）进行聚合
	CreateReport(ctx context.Context, req *Report) (r *v1.Response, err error)
	// 查询报告处理进度（异步模式下使用）
	GetReportTask(ctx context.Context, req *v1.IdRequest) (r *v1.Response, err error)
	// 查询报告基础信息（不包含chunk数据）
	GetReport(ctx context.Context, req *v1.IdRequest) (r *v1.Response, err error)
	// 查询单个chunk数据，基于ChunkID（按需加载）
	GetChunk(ctx context.Context, req *v1.IdRequest) (r *v1.Response, err error)
	// 某个用例的所有数据,基于报告ID（按需加载）
	GetReportChunkList(ctx context.Context, req *v1.IdRequest) (r *v1.Response, err error)
	// 查询报告列表
	ListReport(ctx context.Context, req *v1.QueryRequest) (r *v1.Response, err error)
	// 删除报告
	DeleteReport(ctx context.Context, req *v1.IdRequest) (r *v1.Response, err error)
	// 更新报告
	UpdateReport(ctx context.Context, req *Report) (r *v1.Response, err error)
	// 上传报告图标
	UploadIcon(ctx context.Context, req *UploadIconRequest) (r *v1.Response, err error)
	// 计算报告评分（基于报告配置和用例数据）
	CalculateReportScore(ctx context.Context, req *v1.IdRequest) (r *v1.Response, err error)
	// 重载报告数据（异步处理）
	// 从 Pushgateway 重新查询原始数据并重新聚合
	// 删除旧的 Chunk 数据并生成新的 Chunk
	// 如果配置了评分，会自动重新计算评分
	// 返回任务ID，可通过 GetReportTask 查询进度
	ReloadReport(ctx context.Context, req *v1.IdRequest) (r *v1.Response, err error)
	// 转发报告到其他 MonitorHub（包含完整的 Chunk 数据）
	ForwardReport(ctx context.Context, req *ForwardReportRequest) (r *v1.Response, err error)
	// 导入报告（从其他 MonitorHub 转发过来，保持原始ID）
	ImportReport(ctx context.Context, req *ImportReportRequest) (r *v1.Response, err error)
}

